async function acquireLock(dataFilePath: string): Promise<void> {
	const lock = lockFilePath(dataFilePath);
	const start = Date.now();
	while (true) {
		try {
			const fd = openSync(lock, "wx");
			closeSync(fd);
			return;
		} catch (err: unknown) {
			const nodeErr = err as NodeJS.ErrnoException;
			if (nodeErr.code !== "EEXIST") throw err;
			try {
				const st = statSync(lock);
				if (Date.now() - st.mtimeMs > LOCK_STALE_MS) {
					// Atomic stale-claim. A bare `unlinkSync(lock)` here would be racy:
					// between our stat and unlink another process can win
					// `openSync(wx)` for a fresh lock, and our unlink would then delete
					// their freshly-acquired lock, allowing two writers.
					//
					// Instead, atomically rename `lock` to a unique sidecar. POSIX
					// rename is atomic, so at most one concurrent claimant moves the
					// entry; the others get ENOENT and retry. After the rename, we
					// verify the captured file is the same stale inode we observed
					// (ino + mtime). If it isn't, another claimant has already cycled
					// the lock — restore the sidecar atomically so we don't drop
					// their (now-fresh) lock. We never call `unlinkSync(lock)`
					// directly, so we can no longer delete a path we don't own.
					const sidecar = `${lock}.stale.${randomBytes(8).toString("hex")}`;
					try {
						renameSync(lock, sidecar);
					} catch {
						continue; // another claimant won the rename; retry
					}
					try {
						const stSidecar = statSync(sidecar);
						if (stSidecar.ino === st.ino && stSidecar.mtimeMs === st.mtimeMs) {
							// Captured the stale file we observed; drop it.
							unlinkSync(sidecar);
							continue;
						}
						// Captured a different inode — someone replaced the lock between
						// our stat and our rename. Put it back atomically so the real
						// owner's release still finds it at the canonical path.
						try {
							renameSync(sidecar, lock);
						} catch {
							try {
								unlinkSync(sidecar);
							} catch {
								// best-effort cleanup
							}
						}
					} catch {
						try {
							unlinkSync(sidecar);
						} catch {
							// best-effort cleanup
						}
					}
					continue;
				}
			} catch {
				continue;
			}
			if (Date.now() - start > LOCK_TIMEOUT_MS) {
				throw new Error(`Timeout acquiring lock for ${dataFilePath}`);
			}
			await sleep(LOCK_RETRY_MS + Math.floor(Math.random() * LOCK_RETRY_MS));
		}
	}
}

